FraudInvestigator.Body:
{
    let cust_info = Customers | where customer_id == target_customer_id;
    let cust_accounts = BankAccounts | where customer_id == target_customer_id;
    let cust_txns = Transactions | where customer_id == target_customer_id | order by timestamp desc;
    let fraud_flags = FraudDetection() | where customer_id == target_customer_id and is_fraudulent == true;
    let velocity_flags = VelocityDetection() | where customer_id == target_customer_id;
    let risk_profile = CustomerRiskProfile() | where customer_id == target_customer_id;
    union
        (cust_info | extend section = 'Customer Info' | project section, key = 'Name', value = customer_name),
        (cust_info | extend section = 'Customer Info' | project section, key = 'Email', value = email),
        (cust_info | extend section = 'Customer Info' | project section, key = 'Risk Score', value = tostring(customer_risk_score)),
        (cust_info | extend section = 'Customer Info' | project section, key = 'City', value = city),
        (cust_info | extend section = 'Customer Info' | project section, key = 'Country', value = country),
        (risk_profile | extend section = 'Risk Profile' | project section, key = 'Computed Risk', value = tostring(computed_risk_score)),
        (risk_profile | extend section = 'Risk Profile' | project section, key = 'Risk Category', value = risk_category),
        (risk_profile | extend section = 'Risk Profile' | project section, key = 'Fraud Rate %', value = tostring(fraud_rate)),
        (risk_profile | extend section = 'Risk Profile' | project section, key = 'Total Txns', value = tostring(total_transactions)),
        (risk_profile | extend section = 'Risk Profile' | project section, key = 'Fraud Count', value = tostring(fraud_count))
}

RealTimeFraudDashboard.Body:
{
    let fraud_alerts = FraudDetection() | where is_fraudulent == true;
    let velocity_alerts = VelocityDetection();
    let crossborder_alerts = CrossBorderFraud() | where risk_level == 'Critical';
    let amount_anomalies = AmountAnomalyDetection();
    let unusual_time = UnusualTimeDetection();
    let account_takeover = AccountTakeoverDetection();
    union
        (fraud_alerts | extend detection_type = 'Fraud Score', severity = case(fraud_score >= 90, 'Critical', fraud_score >= 70, 'High', 'Medium') | project timestamp, transaction_id, customer_id, amount, detection_type, severity, details = strcat('Score: ', tostring(fraud_score), ' | Type: ', fraud_type)),
        (velocity_alerts | extend detection_type = 'Velocity', severity = case(high_velocity, 'Critical', 'High') | project timestamp, transaction_id, customer_id, amount, detection_type, severity, details = strcat('Gap: ', tostring(time_diff_minutes), 'min | Merchant: ', merchant_name)),
        (crossborder_alerts | extend detection_type = 'Cross-Border', severity = risk_level | project timestamp, transaction_id, customer_id = customer_name, amount, detection_type, severity, details = strcat(customer_country, ' -> ', merchant_country, ' | ', merchant_name)),
        (amount_anomalies | extend detection_type = 'Amount Anomaly', severity = case(deviation_ratio > 10, 'Critical', 'High') | project timestamp, transaction_id, customer_id = customer_name, amount, detection_type, severity, details = strcat('Deviation: ', tostring(deviation_ratio), 'x avg | Avg: $', tostring(avg_amount))),
        (account_takeover | extend detection_type = 'Account Takeover', severity = threat_level | project timestamp, transaction_id = account_id, customer_id = customer_name, amount = total_amount, detection_type, severity, details = strcat('Txns: ', tostring(transaction_count), ' | Countries: ', tostring(unique_locations)))
    | order by timestamp desc
}

FraudDetection.Body:
{
    Transactions
    | extend hour_of_day = datetime_part('hour', timestamp)
    // Rule 1: Unusual Time (2 AM - 5 AM)
    | extend unusual_time = hour_of_day >= 2 and hour_of_day <= 5
    // Rule 2: Geographic Anomaly (customer and merchant in different countries)
    | extend unusual_location = customer_country != merchant_country
    // Rule 3: High Amount Flag (>$2000)
    | extend amount_flag = amount > 2000
    // Rule 4: High-risk merchant
    | extend high_risk_merchant = merchant_risk_level == "High"
    // Rule 5: High-risk customer
    | extend high_risk_customer = customer_risk_score > 75
    // Rule 6: Card not present for high amounts
    | extend card_not_present_risk = (card_present == false and amount > 500)
    // Calculate fraud score
    | extend fraud_score = 
        case(unusual_time, 15, 0) +
        case(unusual_location, 20, 0) +
        case(amount_flag, 25, 0) +
        case(high_risk_merchant, 10, 0) +
        case(high_risk_customer, 15, 0) +
        case(card_not_present_risk, 20, 0)
    // Determine if fraudulent (score > 70)
    | extend is_fraudulent = fraud_score > 70
    // Classify fraud type
    | extend fraud_type = case(
        is_fraudulent and amount_flag, "Amount Anomaly",
        is_fraudulent and unusual_location, "Geographic Anomaly",
        is_fraudulent and card_not_present_risk, "Card Not Present Fraud",
        is_fraudulent and unusual_time, "Unusual Time Activity",
        is_fraudulent, "Multi-Factor Suspicious",
        "Normal"
    )
}

FraudSummaryKPIs.Body:
{
    let total_txns = Transactions | count | project TotalTransactions = Count;
    let fraud_txns = FraudDetection() | where is_fraudulent == true | summarize FraudCount = count(), FraudAmount = sum(amount);
    let high_risk_customers = Customers | where customer_risk_score > 75 | count | project HighRiskCustomers = Count;
    let active_alerts = FraudAlerts | summarize ActiveAlerts = count();
    let velocity_alerts = VelocityDetection() | summarize VelocityAlerts = count();
    let cross_border = CrossBorderFraud() | where risk_level == 'Critical' | summarize CriticalCrossBorder = count();
    total_txns | extend dummy = 1
    | join kind=inner (fraud_txns | extend dummy = 1) on dummy
    | join kind=inner (high_risk_customers | extend dummy = 1) on dummy
    | join kind=inner (active_alerts | extend dummy = 1) on dummy
    | join kind=inner (velocity_alerts | extend dummy = 1) on dummy
    | join kind=inner (cross_border | extend dummy = 1) on dummy
    | project
        TotalTransactions,
        FraudCount,
        FraudRate = round(100.0 * FraudCount / TotalTransactions, 2),
        FraudAmount = round(FraudAmount, 2),
        HighRiskCustomers,
        ActiveAlerts,
        VelocityAlerts,
        CriticalCrossBorder
}

